#include <stdio.h>
#define MOD 1000000007

long long powmod(long long base, long long exponent) {
    long long result = 1;
    while (exponent > 0) {
        if (exponent % 2 == 1) {
            result = (result * base) % MOD;
        }
        exponent /= 2;
        base = (base * base) % MOD;
    }
    return result;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N;
        scanf("%d", &N);
        int N_bin = 0;
        int temp = N;
        int power = 1;
        while (temp > 0) {
            if (temp % 2 == 1) {
                N_bin += power;
            }
            power *= 10;
            temp /= 2;
        }
        printf("%lld\n", powmod(2, N_bin));
    }
    return 0;
}

